select

from emp_schedule s
         left join emp e on s.emp_id = e.id
         left join dept d on e.dept_id = d.id


        and s.work_date  >=  #{workDateBegin}


        and s.work_date  <=  #{workDateEnd}


        and e.dept_id = #{deptId}


        and s.emp_id = #{empId}


        and s.schedule_type = #{scheduleType}


order by s.work_date desc, s.start_time asc

select count(1)
from emp_schedule s
where s.emp_id = #{empId}
  and s.work_date = #{workDate}
  and s.start_time  <  #{endTime}
  and s.end_time  >  #{startTime}

    and s.id != #{excludeId}

select count(1)
from `order` o
where o.emp_id = #{empId}
  and o.status != 4
  and o.service_time  <  #{rangeEnd}
  and date_add(o.service_time, interval o.duration_minutes minute)  >  #{rangeStart}

select

from emp_schedule s
         left join emp e on s.emp_id = e.id
         left join dept d on e.dept_id = d.id
where s.work_date = #{workDate}

    and e.dept_id = #{deptId}


    and s.emp_id = #{empId}

order by s.start_time asc

select s.id, s.emp_id as empId, e.name as empName, s.work_date as workDate, s.start_time as startTime, s.end_time as endTime, s.schedule_type as scheduleType, s.max_appointments as maxAppointments, s.remark from emp_schedule s left join emp e on s.emp_id = e.id where s.work_date = #{workDate} and s.schedule_type = 1
and s.emp_id = #{empId}
order by s.start_time asc

select s.id, s.emp_id as empId, e.name as empName, s.work_date as workDate, s.start_time as startTime, s.end_time as endTime, s.schedule_type as scheduleType, s.max_appointments as maxAppointments, s.remark from emp_schedule s left join emp e on s.emp_id = e.id where s.work_date = #{workDate} and s.schedule_type = 1 and s.emp_id in
#{empId}
order by s.start_time asc

