update emp_schedule
set schedule_type = 5
where emp_id = #{empId}
  and work_date = #{workDate}
  and schedule_type = 1
  and start_time  <=  #{rangeStart}
  and end_time  >=  #{rangeEnd}
order by timestampdiff(second, start_time, end_time) asc
limit 1

update emp_schedule
set schedule_type = 1
where emp_id = #{empId}
  and work_date = #{workDate}
  and schedule_type = 5
  and start_time  <=  #{rangeStart}
  and end_time  >=  #{rangeEnd}
order by timestampdiff(second, start_time, end_time) asc
limit 1
